import { TextureDataType } from "three/src/constants.js";
import { RenderTarget } from "three/src/core/RenderTarget.js";
import TextureNode from "three/src/nodes/accessors/TextureNode.js";
import Node from "../core/Node.js";

export interface RTTNodeOptions {
    type: TextureDataType;
}

declare class RTTNode extends TextureNode {
    readonly isRTTNode: true;

    node: Node;
    width: number | null;
    height: number | null;

    renderTarget: RenderTarget | null;

    textureNeedsUpdate: boolean;
    autoUpdate: boolean;

    pixelRatio?: number;

    constructor(node: Node, width?: number | null, height?: number | null, options?: RTTNodeOptions);

    get autoResize(): boolean;

    setSize(width: number | null, height: number | null): void;

    setPixelRatio(pixelRatio: number): void;
}

export default RTTNode;

export const rtt: (
    node: Node,
    width?: number | null,
    height?: number | null,
    options?: RTTNodeOptions,
) => RTTNode;
export const convertToTexture: (
    node: Node,
    width?: number | null,
    height?: number | null,
    options?: RTTNodeOptions,
) => RTTNode;
